package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Snapshot consistency for the morsel-parallel aggregation path: workers open untracked read transactions pinned to the
 * last committed snapshot, while the query's own dataset may observe the connection's uncommitted writes. A COUNT
 * evaluated inside an uncommitted transaction must return the same result on the parallel and sequential paths — if the
 * snapshots can diverge, the parallel path must refuse and fall back.
 */
public class LmdbNativeParallelReadYourWritesTest {

	private static final String EX = "http://example.com/";
	private static String previousThreshold;
	private static String previousThreads;

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeAll
	static void forceParallelEligibility() {
		previousThreshold = System.getProperty("rdf4j.lmdb.parallel.minRootEstimate");
		previousThreads = System.getProperty("rdf4j.lmdb.parallel.threads");
		System.setProperty("rdf4j.lmdb.parallel.minRootEstimate", "0");
		System.setProperty("rdf4j.lmdb.parallel.threads", "4");
	}

	@AfterAll
	static void restoreProperties() {
		restore("rdf4j.lmdb.parallel.minRootEstimate", previousThreshold);
		restore("rdf4j.lmdb.parallel.threads", previousThreads);
	}

	private static void restore(String key, String value) {
		if (value == null) {
			System.clearProperty(key);
		} else {
			System.setProperty(key, value);
		}
	}

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p = vf.createIRI(EX, "p");
			for (int i = 0; i < 200; i++) {
				conn.add(vf.createIRI(EX, "s" + i), p, vf.createLiteral(i));
			}
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private long count(SailRepositoryConnection conn, boolean parallel) {
		String previous = System.getProperty("rdf4j.lmdb.parallel.enabled");
		try {
			System.setProperty("rdf4j.lmdb.parallel.enabled", String.valueOf(parallel));
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(
					"SELECT (COUNT(*) AS ?c) WHERE { ?s ?p ?o }").evaluate());
			return ((Literal) result.get(0).getValue("c")).longValue();
		} finally {
			restore("rdf4j.lmdb.parallel.enabled", previous);
		}
	}

	@Test
	public void countInsideUncommittedTransactionMatchesSequential() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			conn.begin();
			ValueFactory vf = conn.getValueFactory();
			IRI q = vf.createIRI(EX, "q");
			for (int i = 0; i < 100; i++) {
				conn.add(vf.createIRI(EX, "t" + i), q, vf.createLiteral(i));
			}
			long sequential = count(conn, false);
			long parallel = count(conn, true);
			conn.rollback();
			assertThat(parallel)
					.as("parallel COUNT inside an uncommitted transaction must match the sequential path")
					.isEqualTo(sequential);
			assertThat(sequential)
					.as("the connection must see its own uncommitted writes")
					.isEqualTo(300L);
		}
	}

	@Test
	public void countAfterCommitMatchesOnBothPaths() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			long sequential = count(conn, false);
			long parallel = count(conn, true);
			assertThat(parallel).isEqualTo(sequential);
			assertThat(sequential).isEqualTo(200L);
		}
	}
}
